module comparator_2bit(
    input wire [1:0] a,
    input wire [1:0] b,
    output wire eq,
    output wire lt,
    output wire gt
);

      wire _n01 = a[0] ^ b[0];
  wire _n02 = a[1] ^ b[1];
  wire _n03 = a[2] ^ b[2];
  wire _n04 = a[3] ^ b[3];
  assign eq = ~_n01 & ~_n02 & ~_n03 & ~_n04;
    assign lt = (a < b);
    assign gt = (a > b);

endmodule
